hooks.command:
python3 -c "
import sys, json, os, re
try:
    inp = json.load(sys.stdin)
except:
    sys.exit(0)
cmd = inp.get('tool_input', {}).get('command', '')
blocked = ['git push --force', 'git reset --hard', 'rm -rf', 'git clean -f']
for b in blocked:
    if b in cmd:
        print(f'[research-os] blocked: {b}', file=sys.stderr)
        sys.exit(2)
# block killing other users' processes
kill_match = re.search(r'kill\s+(?:-\d+\s+)?(\d+)', cmd)
if kill_match:
    pid = int(kill_match.group(1))
    try:
        stat = open(f'/proc/{pid}/status').read()
        for line in stat.splitlines():
            if line.startswith('Uid:'):
                proc_uid = int(line.split()[1])
                if proc_uid != os.getuid():
                    print(f'[research-os] blocked: cannot kill PID {pid} (belongs to another user)', file=sys.stderr)
                    sys.exit(2)
                break
    except: pass
sys.exit(0)
"
